$(".tab-selector").click(function (t) {
    $("html, body").stop(),
        $(".tabOpt").hide(),
        $(".tabs li.tab-selector").removeClass("is-active"),
        $("." + $(this).attr("rel") + "-li").addClass("is-active"),
        $("." + $(this).attr("rel")).show(),
        t.preventDefault(),
        $("html, body")
            .stop()
            .animate({ scrollTop: +$(".tabs").offset().top }, 700);
}),
    $(".goTop").click(function (t) {
        $("html, body").stop(),
            t.preventDefault(),
            $("html, body")
                .stop()
                .animate({ scrollTop: +$(".topGo").offset().top }, 500);
    });
